package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testGetCommentMarker() {
        // Given
        Character expected = null; // Default value in CSVFormat.DEFAULT

        // When
        Character actual = csvFormat.getCommentMarker();

        // Then
        assertEquals(expected, actual);
    }

    @Test
    public void testSetCommentMarker() throws Exception {
        // Given
        Character commentMarker = '#';

        // When
        csvFormat = csvFormat.withCommentMarker(commentMarker);
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);
        Character actual = (Character) commentMarkerField.get(csvFormat);

        // Then
        assertEquals(commentMarker, actual);
    }
}
